// Public cloud: Azure Container Apps + Azure SQL Managed Instance
// Full managed service — no VMs to patch, HA built in

param location string = 'eastus'
param sqlAdminPassword string

resource env 'Microsoft.App/managedEnvironments@2023-05-01' = {
  name: 'prod-env'
  location: location
  properties: { appLogsConfiguration: { destination: 'log-analytics' } }
}

resource api 'Microsoft.App/containerApps@2023-05-01' = {
  name: 'api'
  location: location
  properties: {
    managedEnvironmentId: env.id
    template: {
      containers: [{ name: 'api', image: 'myacr.azurecr.io/api:v1', resources: { cpu: '0.5', memory: '1Gi' } }]
      scale: { minReplicas: 1, maxReplicas: 50 }  // auto-scale to 50 replicas
    }
  }
}

resource db 'Microsoft.Sql/servers/databases@2023-05-01-preview' = {
  // Azure SQL — no VM, no OS, no backups to configure
  // SLA: 99.99%, automatic failover groups available
  name: 'prod-sql/orders'
  location: location
  sku: { name: 'GP_Gen5_2', tier: 'GeneralPurpose' }
}

// Hybrid: API in Azure Container Apps, database on-premises
// Network: ExpressRoute private peering connects Azure VNet to on-prem SQL

// Azure side: Container App connecting to on-prem SQL via private IP
resource api 'Microsoft.App/containerApps@2023-05-01' = {
  name: 'api'
  location: 'eastus'
  properties: {
    managedEnvironmentId: env.id
    template: {
      containers: [{
        name: 'api'
        image: 'myacr.azurecr.io/api:v1'
        env: [
          { name: 'DB_HOST', value: '10.0.1.50' }   // on-prem SQL private IP via ExpressRoute
          { name: 'DB_PORT', value: '1433' }
        ]
        resources: { cpu: '0.5', memory: '1Gi' }
      }]
      scale: { minReplicas: 2, maxReplicas: 100 }    // scales independently of on-prem DB
    }
    configuration: {
      // VNet integration: Container App joins Azure VNet that peers to on-prem via ExpressRoute
      ingress: { external: true, targetPort: 8080 }
    }
  }
}
// On-premises side: SQL Server VM (you manage)
// ExpressRoute circuit connects Azure VNet 10.10.0.0/16 to on-prem 10.0.0.0/8
// Latency: ~5ms via ExpressRoute vs ~1ms on-prem — acceptable for most OLTP
